// Generated by Claude Sonnet 4.5

import { BackupStatus } from '@eclipse-che/common';
import { createSelector } from '@reduxjs/toolkit';

import { RootState } from '@/store';

/**
 * Base selector for the entire backups state slice
 */
const selectBackupsState = (state: RootState) => state.backups;

/**
 * Basic Selectors
 */

/**
 * Select the byWorkspace map (all workspace backup info indexed by UID)
 */
// Generated by Claude Sonnet 4.6
export const selectAllBackupsByWorkspace = createSelector(
  selectBackupsState,
  state => state.byWorkspace,
);

/**
 * Select the loading state for all backup operations
 */
export const selectBackupsLoading = createSelector(selectBackupsState, state => state.loading);

/**
 * Select the error message if any operation failed
 */
export const selectBackupsError = createSelector(selectBackupsState, state => state.error);

/**
 * Workspace Selectors
 */

/**
 * Select backup info for a specific workspace by UID
 * Returns undefined if workspace has no backup info
 */
export const selectWorkspaceBackupInfo = createSelector(
  [selectBackupsState, (_state: RootState, workspaceUID: string) => workspaceUID],
  (backups, workspaceUID) => backups.byWorkspace[workspaceUID],
);

/**
 * Select just the backup status for a specific workspace
 * Returns BackupStatus.NEVER if workspace has no backup info
 */
export const selectWorkspaceBackupStatus = createSelector(
  [selectBackupsState, (_state: RootState, workspaceUID: string) => workspaceUID],
  (backups, workspaceUID) => backups.byWorkspace[workspaceUID]?.status || BackupStatus.NEVER,
);

/**
 * Check if a workspace has any backup info
 * Returns true if backup info exists (regardless of status)
 */
export const selectWorkspaceHasBackup = createSelector(
  [selectBackupsState, (_state: RootState, workspaceUID: string) => workspaceUID],
  (backups, workspaceUID) => {
    const info = backups.byWorkspace[workspaceUID];
    return !!info && info.status !== BackupStatus.NEVER;
  },
);

/**
 * Namespace Selectors
 */

/**
 * Select all backup items for a specific namespace
 * Returns empty array if namespace has no backups
 */
export const selectNamespaceBackups = createSelector(
  [selectBackupsState, (_state: RootState, namespace: string) => namespace],
  (backups, namespace) => backups.byNamespace[namespace] || [],
);

/**
 * Select the count of backups in a specific namespace
 */
export const selectNamespaceBackupCount = createSelector(
  [selectBackupsState, (_state: RootState, namespace: string) => namespace],
  (backups, namespace) => backups.byNamespace[namespace]?.length || 0,
);

/**
 * Memoized Selectors
 */

/**
 * Select filtered backup items for a namespace, optionally filtered by workspace name
 * Returns all backups for namespace if workspaceName is not provided
 * Returns only matching backups if workspaceName is provided
 */
export const selectFilteredNamespaceBackups = createSelector(
  [
    selectBackupsState,
    (_state: RootState, namespace: string) => namespace,
    (_state: RootState, _namespace: string, workspaceName?: string) => workspaceName,
  ],
  (backups, namespace, workspaceName) => {
    const namespaceBackups = backups.byNamespace[namespace] || [];

    if (!workspaceName) {
      return namespaceBackups;
    }

    return namespaceBackups.filter(backup => backup.workspaceName === workspaceName);
  },
);

/**
 * Select array of workspace UIDs that have backups
 * Useful for filtering workspace lists to show only backed-up workspaces
 */
export const selectWorkspacesWithBackups = createSelector(selectBackupsState, backups => {
  return Object.keys(backups.byWorkspace).filter(workspaceUID => {
    const info = backups.byWorkspace[workspaceUID];
    return info && info.status !== BackupStatus.NEVER;
  });
});

/**
 * Select all backup items across all namespaces
 * Returns a flat array of all backup items
 */
export const selectAllBackupItems = createSelector(selectBackupsState, backups => {
  return Object.values(backups.byNamespace).flat();
});

/**
 * Select cluster-wide backup configuration
 */
export const selectBackupConfig = createSelector(selectBackupsState, state => state.backupConfig);

/**
 * Select the next scheduled backup time from cluster backup config
 * Returns undefined if config is not loaded, backup is disabled, or schedule is not set
 */
export const selectNextScheduledBackup = createSelector(selectBackupsState, state =>
  state.backupConfig?.enabled ? state.backupConfig.nextScheduledBackup : undefined,
);

/**
 * Select loading state flags individually
 */
export const selectIsLoadingBackups = createSelector(
  selectBackupsState,
  state => state.loading.loadingCount > 0,
);

export const selectIsUpdatingBackups = createSelector(
  selectBackupsState,
  state => state.loading.updatingCount > 0,
);

export const selectIsValidatingBackup = createSelector(
  selectBackupsState,
  state => state.loading.validatingCount > 0,
);
